module RefModule (
    input wire data_in,
    input wire write_enable,
    input wire read_enable,
    output reg data_out
);
    reg unused_stored_data;

    always @(*) begin
        if (write_enable) begin
            unused_stored_data <= data_in;
        end
        if (read_enable) begin
            data_out <= unused_stored_data;
        end
    end
endmodule
